class RoomProcessor {
    private RoomStrategy strategy;

    public void setStrategy(RoomStrategy strategy) {
        this.strategy = strategy;
    }

    public void process() {
        if (strategy == null) {
            throw new IllegalStateException("未设置房间处理策略");
        }
        strategy.execute();
    }
}

