        return Objects.equals(id, vehicle.id);
    }

    @Override
    public int hashCode() {
        return Objects.hash(id);
    }

    @Override
    public int compareTo(Vehicle other) {
        return this.id.compareTo(other.id);
    }

    @Override
    public String toString() {
        return "Vehicle{id='" + id + "', brand='" + brand + "'}";
    }
}

