        // 使用 HashSet 去重
        Set<Device> deviceSet = new HashSet<>();
        deviceSet.add(new Device("A002", "智能门锁"));
        deviceSet.add(new Device("A001", "智能灯"));
        deviceSet.add(new Device("A003", "智能空调"));
